CREATE VIEW `ads_alg_cd_video_shortvideo_reco_view` (`dt` COMMENT "日期", `event_name` COMMENT "事件名称", `event_time` COMMENT "事件时间", `event_time_add` COMMENT "事件时间(加8小时后的)", `account_id` COMMENT "用户ID", `scene_id` COMMENT "推荐场景", `trace_id` COMMENT "唯一请求追踪字符串", `series_id` COMMENT "剧ID", `index_i` COMMENT "排序", `reqstr` COMMENT "请求字符串", `extend_map` COMMENT "扩展map", `feature_map` COMMENT "特征map")
COMMENT "算法日志-事件-shortvideo_reco" AS SELECT date(hours_add(`ods_log`.`ods_alg_cd_video_shortvideo_reco`.`event_time`, 8)) AS `dt`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`event_name`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`event_time`, hours_add(`ods_log`.`ods_alg_cd_video_shortvideo_reco`.`event_time`, 8) AS `event_time_add`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`account_id`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`scene_id`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`trace_id`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`series_id`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`index_i`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`reqstr`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`extend_map`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`feature_map`
FROM `ods_log`.`ods_alg_cd_video_shortvideo_reco`
WHERE (`ods_log`.`ods_alg_cd_video_shortvideo_reco`.`dt` < '2024-03-20') AND ((date(hours_add(`ods_log`.`ods_alg_cd_video_shortvideo_reco`.`event_time`, 8))) < '2024-03-20') UNION ALL SELECT date(`ods_log`.`ods_alg_cd_video_shortvideo_reco`.`event_time`) AS `dt`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`event_name`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`event_time`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`event_time` AS `event_time_add`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`account_id`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`scene_id`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`trace_id`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`series_id`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`index_i`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`reqstr`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`extend_map`, `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`feature_map`
FROM `ods_log`.`ods_alg_cd_video_shortvideo_reco`
WHERE `ods_log`.`ods_alg_cd_video_shortvideo_reco`.`dt` >= '2024-03-20';